import 'dart:io';
Future<void> uploadLargeVideo(File file) async {
  final stream = file.openRead();
  final length = await file.length();

  final form = FormData.fromMap({
    'video': MultipartFile.fromStream(
      () => stream,
      length,
      filename: file.uri.pathSegments.last,
      contentType: DioMediaType('video', 'mp4'),
    ),
  });
  await dio.post('/upload', data: form);
}

// ── Presigned PUT — bypass multipart entirely ──
// 1) Server returns a presigned URL with method: PUT, headers: { 'Content-Type': 'image/jpeg' }
// 2) Client uploads bytes directly; no multipart needed
Future<void> directUpload(String url, List<int> bytes) async {
  await Dio().put(url, data: Stream.fromIterable([bytes]),
      options: Options(
        headers: {'Content-Type': 'image/jpeg', 'Content-Length': '${bytes.length}'},
      ));
}

