import 'package:dio/dio.dart';
import 'package:dio_cache_interceptor/dio_cache_interceptor.dart';
import 'package:dio_cache_interceptor_hive_store/dio_cache_interceptor_hive_store.dart';

Future<Dio> buildCachedDio() async {
  final cacheDir = (await getTemporaryDirectory()).path;
  final store = HiveCacheStore(cacheDir, hiveBoxName: 'http_cache');

  final options = CacheOptions(
    store: store,
    policy: CachePolicy.request,                   // honor server Cache-Control
    hitCacheOnErrorExcept: const [401, 403],       // serve cache on network failure
    maxStale: const Duration(days: 7),              // accept stale up to a week
    keyBuilder: CacheOptions.defaultCacheKeyBuilder,
  );

  final dio = Dio(BaseOptions(baseUrl: 'https://api.example.com'));
  dio.interceptors.add(DioCacheInterceptor(options: options));
  return dio;
}

