// ── 2) App-level stale-while-revalidate ──
class ProductsRepo {
  final Dio _dio;
  final Box<Product> _cache;
  ProductsRepo(this._dio, this._cache);

  Stream<List<Product>> watch() async* {
    // 1) Emit cache immediately
    final cached = _cache.values.toList();
    if (cached.isNotEmpty) yield cached;

    // 2) Refresh in background
    try {
      final fresh = await _fetchFresh();
      await _cache.clear();
      await _cache.addAll(fresh);
      yield fresh;
    } catch (e) {
      // Network failed; the cached emit (if any) is still on screen
    }
  }

  Future<List<Product>> _fetchFresh() async {
    final r = await _dio.get('/products');
    return (r.data as List).map((e) => Product.fromJson(e)).toList();
  }
}

