import 'dart:async';
import 'package:web_socket_channel/web_socket_channel.dart';

enum WsState { disconnected, connecting, connected }

class ChatClient {
  final Uri uri;
  WebSocketChannel? _ch;
  StreamSubscription? _sub;
  Timer? _backoff;
  Timer? _heartbeat;
  int _attempt = 0;
  WsState _state = WsState.disconnected;

  final _events = StreamController<dynamic>.broadcast();
  Stream<dynamic> get events => _events.stream;

  ChatClient(this.uri);

  void connect() {
    if (_state != WsState.disconnected) return;
    _state = WsState.connecting;
    _ch = WebSocketChannel.connect(uri);

    _sub = _ch!.stream.listen(
      (msg) {
        if (_state != WsState.connected) {
          _state = WsState.connected;
          _attempt = 0;
          _startHeartbeat();
        }
        _events.add(msg);
      },
      onError: (e) => _scheduleReconnect(),
      onDone: _scheduleReconnect,
      cancelOnError: true,
    );
  }

  void send(Object msg) {
    if (_state == WsState.connected) _ch?.sink.add(msg);
  }

  void _startHeartbeat() {
    _heartbeat?.cancel();
    _heartbeat = Timer.periodic(const Duration(seconds: 25), (_) {
      try { _ch?.sink.add('ping'); } catch (_) { _scheduleReconnect(); }
    });
  }

  void _scheduleReconnect() {
    _heartbeat?.cancel();
    _sub?.cancel();
    _ch?.sink.close().catchError((_) {});
    _ch = null;
    _state = WsState.disconnected;

    final delay = Duration(milliseconds: _backoffMs(_attempt));
    _attempt++;
    _backoff = Timer(delay, connect);
  }

  int _backoffMs(int n) {
    final base = 1000 * (1 << n.clamp(0, 5));   // 1s, 2s, 4s ... 32s
    final jitter = (DateTime.now().millisecondsSinceEpoch % 500);
    return (base + jitter).clamp(1000, 60000);
  }

  void dispose() {
    _backoff?.cancel();
    _heartbeat?.cancel();
    _sub?.cancel();
    _ch?.sink.close();
    _events.close();
  }
}

// ── Wire to app lifecycle ──
class _ChatPageState extends State<ChatPage> with WidgetsBindingObserver {
  late final _client = ChatClient(Uri.parse('wss://api.example.com/socket'));

  @override
  void initState() { super.initState(); WidgetsBinding.instance.addObserver(this); _client.connect(); }
  @override
  void dispose() { WidgetsBinding.instance.removeObserver(this); _client.dispose(); super.dispose(); }

  @override
  void didChangeAppLifecycleState(AppLifecycleState s) {
    if (s == AppLifecycleState.resumed)  _client.connect();
    if (s == AppLifecycleState.paused)   _client.dispose();   // or just disconnect
  }
}

// ── Domain hierarchy ──
sealed class AppError implements Exception { final String message; const AppError(this.message); }
class NetworkError      extends AppError { const NetworkError([super.m = 'No network']); }
class TimeoutError      extends AppError { const TimeoutError([super.m = 'Timeout']); }
class ServerError       extends AppError { final int statusCode; const ServerError(this.statusCode, [super.m = 'Server error']); }
class BadRequestError   extends AppError {
  final Map<String, String> fieldErrors;
  const BadRequestError(super.message, this.fieldErrors);
}
class UnauthorizedError extends AppError { const UnauthorizedError([super.m = 'Sign in required']); }
class ForbiddenError    extends AppError { const ForbiddenError([super.m = 'No access']); }
class NotFoundError     extends AppError { const NotFoundError([super.m = 'Not found']); }
class CancelledError    extends AppError { const CancelledError([super.m = 'Cancelled']); }

// ── Mapper ──
AppError mapDioError(DioException e) {
  switch (e.type) {
    case DioExceptionType.cancel:
      return const CancelledError();
    case DioExceptionType.connectionTimeout:
    case DioExceptionType.sendTimeout:
    case DioExceptionType.receiveTimeout:
      return const TimeoutError();
    case DioExceptionType.connectionError:
    case DioExceptionType.badCertificate:
      return const NetworkError();
    case DioExceptionType.badResponse:
      final code = e.response?.statusCode ?? 0;
      switch (code) {
        case 400: return BadRequestError(
          (e.response?.data?['message'] as String?) ?? 'Bad request',
          _extractFieldErrors(e.response?.data),
        );
        case 401: return const UnauthorizedError();
        case 403: return const ForbiddenError();
        case 404: return const NotFoundError();
        default:  return ServerError(code);
      }
    case DioExceptionType.unknown:
      return NetworkError(e.message ?? 'Unknown network error');
  }
}

Map<String, String> _extractFieldErrors(dynamic body) {
  if (body is! Map) return const {};
  final errs = body['errors'];
  if (errs is! Map) return const {};
  return errs.map((k, v) => MapEntry('$k', '$v'));
}

// ── Interceptor — translate at the boundary ──
class ErrorMappingInterceptor extends Interceptor {
  @override
  void onError(DioException err, ErrorInterceptorHandler handler) {
    handler.reject(DioException(
      requestOptions: err.requestOptions,
      error: mapDioError(err),                // ✅ wrap the domain error in DioException.error
      type: err.type,
      response: err.response,
      stackTrace: err.stackTrace,
    ));
  }
}

