// ── Tables ──
// notes        (id, body, updated_at, server_id, dirty)
// pending_ops  (id, op, table, row_id, payload, attempts, last_error, idempotency_key)

import 'package:uuid/uuid.dart';
final _uuid = const Uuid();

class NotesRepo {
  final Database db;
  NotesRepo(this.db);

  Future<void> create(String body) async {
    final clientId = _uuid.v4();
    final idemp    = _uuid.v4();
    await db.transaction((txn) async {
      await txn.insert('notes', {
        'id': clientId, 'body': body, 'updated_at': DateTime.now().toIso8601String(),
        'server_id': null, 'dirty': 1,
      });
      await txn.insert('pending_ops', {
        'id': _uuid.v4(),
        'op': 'create_note', 'table': 'notes', 'row_id': clientId,
        'payload': jsonEncode({'body': body}),
        'idempotency_key': idemp,
        'attempts': 0,
      });
    });
    SyncEngine.instance.kick();   // wake the worker
  }
}

class SyncEngine {
  static final SyncEngine instance = SyncEngine._();
  SyncEngine._();
  final _lock = Lock();
  final api = Dio();

  Future<void> kick() async {
    await _lock.synchronized(_drainOnce);
  }

  Future<void> _drainOnce() async {
    while (true) {
      final op = await db.query('pending_ops', orderBy: 'id', limit: 1);
      if (op.isEmpty) return;
      final row = op.first;
      try {
        await _apply(row);
        await db.delete('pending_ops', where: 'id = ?', whereArgs: [row['id']]);
      } on AppError catch (e) {
        if (e is BadRequestError || e is ForbiddenError) {
          // Non-retryable — surface to user, drop the op
          await db.delete('pending_ops', where: 'id = ?', whereArgs: [row['id']]);
          rethrow;
        }
        await db.update('pending_ops',
          {'attempts': (row['attempts'] as int) + 1, 'last_error': '$e'},
          where: 'id = ?', whereArgs: [row['id']]);
        // Backoff outside this loop
        await Future.delayed(const Duration(seconds: 5));
      }
    }
  }

  Future<void> _apply(Map<String, Object?> op) async {
    final payload = jsonDecode(op['payload'] as String) as Map<String, dynamic>;
    final res = await api.post(
      '/${op['table']}',
      data: payload,
      options: Options(headers: {'Idempotency-Key': op['idempotency_key']}),
    );
    final serverId = res.data['id'];
    await db.update('notes',
      {'server_id': serverId, 'dirty': 0},
      where: 'id = ?', whereArgs: [op['row_id']]);
  }
}

// ── Pull updates since last cursor ──
Future<void> pull() async {
  final cursor = (await db.query('sync_meta', where: 'key = ?', whereArgs: ['notes_cursor']))
      .firstOrNull?['value'] as String?;
  final res = await api.get('/notes', queryParameters: {if (cursor != null) 'after': cursor});
  for (final n in res.data['items']) {
    await db.insert('notes', n, conflictAlgorithm: ConflictAlgorithm.replace);
  }
  await db.insert('sync_meta',
    {'key': 'notes_cursor', 'value': res.data['next_cursor']},
    conflictAlgorithm: ConflictAlgorithm.replace);
}

