Future<GraphQLClient> buildClient() async {
  final HttpLink httpLink = HttpLink('https://api.example.com/graphql');

  final AuthLink authLink = AuthLink(
    getToken: () async {
      final tok = await tokens.read();
      return tok == null ? null : 'Bearer $tok';
    },
  );

  final WebSocketLink wsLink = WebSocketLink(
    'wss://api.example.com/graphql',
    config: SocketClientConfig(
      autoReconnect: true,
      inactivityTimeout: const Duration(seconds: 30),
    ),
  );

  // Use ws for subscriptions, http for queries+mutations
  final Link link = Link.split((req) => req.isSubscription, wsLink, authLink.concat(httpLink));

  await initHiveForFlutter();
  return GraphQLClient(
    link: link,
    cache: GraphQLCache(store: HiveStore()),
  );
}

